diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..6378d46b88d4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3149,6 +3149,33 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
       }
     }
   }
+  // select (select C1, C2, false), c, (select C1, a, b) -> select C1, (select C2, c, a), b
+  // This folds a select with AND-like condition into the nested select structure.
+  // Only apply if the condition select and false value select have single uses
+  // to avoid breaking extra uses.
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    if (auto *FalseC = dyn_cast<ConstantInt>(CondSI->getFalseValue())) {
+      if (FalseC->isZero()) {
+        if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+          if (CondSI->getCondition() == FalseSI->getCondition() &&
+              CondSI->hasOneUse() && FalseSI->hasOneUse()) {
+            // C1 = CondSI->getCondition()
+            // C2 = CondSI->getTrueValue()
+            // a = FalseSI->getTrueValue()
+            // b = FalseSI->getFalseValue()
+            // c = TrueVal
+            Value *C1 = CondSI->getCondition();
+            Value *C2 = CondSI->getTrueValue();
+            Value *a = FalseSI->getTrueValue();
+            Value *b = FalseSI->getFalseValue();
+            Value *InnerSel = Builder.CreateSelect(C2, TrueVal, a, SI.getName() + ".in");
+            return SelectInst::Create(C1, InnerSel, b, SI.getName());
+          }
+        }
+      }
+    }
+  }
+

